`timescale 1ns / 1ns

// Name: IQ interpolator
//% Takes interleaved I-Q, produces interpolated,
//% separate streams ready for upconversion
module fiq_interp #(
	parameter a_dw=16,
	parameter i_dw=17,
	parameter q_dw=17
) (
	input clk,
	input signed [a_dw-1:0] a_data,  // Interleaved I-Q Data
	input a_gate,  // Data valid gate
	input a_trig,  // 1 bit information telling data is I or Q
	output signed [i_dw-1:0] i_data,
	output i_gate,
	output i_trig,
	output signed [q_dw-1:0] q_data,
	output q_gate,
	output q_trig,
	output time_err
);

wire iq_sync = a_trig;
reg signed [a_dw-1:0] iq_in1=0, iq_in2=0;
always @(posedge clk) begin
	iq_in1 <= a_data;
	iq_in2 <= iq_in1;
end
wire signed [a_dw-1:0] i_raw = iq_sync ? iq_in1 : a_data;
wire signed [a_dw-1:0] q_raw = iq_sync ? iq_in2 : iq_in1;

reg signed [a_dw-1:0] i_raw1=0, q_raw1=0;
reg signed [a_dw  :0] i2i=0, i2q=0;
always @(posedge clk) begin
	i_raw1 <= i_raw;
	q_raw1 <= q_raw;
	i2i <= i_raw + i_raw1;
	i2q <= q_raw + q_raw1;
end

reg last_sync=0, time_err_r=0;
always @(posedge clk) begin
	last_sync <= iq_sync;
	time_err_r <= ~a_gate | (iq_sync & ~last_sync);
end

assign i_data = i2i;
assign i_gate = 1'b1;
assign i_trig = 1'b1;
assign q_data = i2q;
assign q_gate = 1'b1;
assign q_trig = 1'b1;
assign time_err = time_err_r;

endmodule

`timescale 1ns / 1ns

// Name: Set carrier level from I and Q
//% Provide LO at cosd and sind ports
// Essentially a dot product of the LO signal [cosd, sind] with [i_data, q_data]
// N.B.: full-scale negative is an invalid LO value.
module flevel_set #(
	parameter i_dw=17, // XXX don't change this
	parameter q_dw=17, // XXX don't change this
	parameter o_dw=16  // XXX don't change this
) (
	input clk,
	input signed [17:0] cosd,  // LO input
	input signed [17:0] sind,  // LO input
	input signed [i_dw-1:0] i_data,
	input i_gate,
	input i_trig,  // I baseband
	input signed [q_dw-1:0] q_data,
	input q_gate,
	input q_trig,  // Q baseband
	output signed [o_dw-1:0] o_data,
	output o_gate, o_trig, // carrier
	output time_err
);

`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
reg signed [34:0] cosp = 0, sinp = 0;  // 17-bit i_data * 18-bit cosd
wire signed [16:0] cosp_msb = cosp[33:17];
wire signed [16:0] sinp_msb = sinp[33:17];
reg signed [17:0] sum = 0;
reg signed [16:0] sum2 = 0;
always @(posedge clk) begin
	cosp <= i_data * cosd;
	sinp <= q_data * sind;
	sum <= cosp_msb + sinp_msb + 1;
	sum2 <= `SAT(sum,17,16);
end

reg time_err_r=0;
always @(posedge clk) begin
	time_err_r <= ~i_gate | ~q_gate;
end

`undef SAT

assign o_data = sum2[16:1];
assign o_gate = 1'b1;
assign o_trig = 1'b0;
assign time_err = time_err_r;

endmodule

`timescale 1ns / 1ns
// SSB stands for Single Side Band.
// https://en.wikipedia.org/wiki/Single-sideband_modulation
// (Almost) pin compatible with second_if_out,
// but this one relies on interpolators (afterburner) to up-sample the output
// data to DDR so it can drive a double-frequency DAC.
//
// It nominally produces an I and Q drive output but single-drive usage is possible
// by simply leaving dac2_out{0,1} floating, letting the synthesizer optimize-away
// the redundant code.
//
// Directly uses the provided LO (cosa,sina), thus output IF will be determined by
// the LO frequency

module ssb_out (
	input clk,
	input [1:0] div_state,      // div_state [0] I-Q signal
	input signed [17:0] drive,  // Baseband interleaved I-Q
	input enable,               // Set output on enable else 0
	input ssb_flip,             // Flips sign of dac2_out output pair
	input [15:0] aftb_coeff,    // Coefficient to correct for the linear interpolation between
				    // two consecutive samples; see afterburner.v for details.
				    // Example based on FNAL test:
				    // 1313 MHz LO as timebase, / 16 to get 82.0625 MHz ADC clk
				    // IF is 13 MHz, 16/101 = 0.1584 of ADC clk
				    // aftb_coeff = ceil(32768*0.5*sec(2*pi*16/101/2)) = 18646
	// local oscillator
	input signed [17:0] cosa,
	input signed [17:0] sina,
	// DDR on both DACs
	output signed [15:0] dac1_out0, // Nominally in-phase component
	output signed [15:0] dac1_out1,
	output signed [15:0] dac2_out0, // Nominally quadrature component
	output signed [15:0] dac2_out1
);

wire iq = div_state[0];

// Bring input I and Q to full data rate
wire signed [16:0] drive_i, drive_q;
fiq_interp interp(.clk(clk),
	.a_data(drive[17:2]), .a_gate(1'b1), .a_trig(iq),
	.i_data(drive_i), .q_data(drive_q));

wire signed [15:0] out1, out2;

// SSB modulation scheme (Hartley modulator) using dot-product for LSB selection:
// (I, Q) . (cos(wLO*t), sin(wLO*t)) = I*cos(wLO*t) + Q*sin(wLO*t)

// In-phase portion of SSB drive signal
flevel_set level1(.clk(clk),
	.cosd(cosa), .sind(sina),
	.i_data(drive_i), .i_gate(1'b1), .i_trig(1'b1),
	.q_data(drive_q), .q_gate(1'b1), .q_trig(1'b1),
	.o_data(out1));

wire signed [15:0] outk1 = enable ? out1 : 0;

wire [15:0] dac1_ob0, dac1_ob1;  // offset binary outputs from afterburner
afterburner afterburner1(.clk(clk),
	.data({outk1,1'b0}), .coeff(aftb_coeff),
	.data_out0(dac1_ob0), .data_out1(dac1_ob1));

// Second (optional) dot-product with 90deg-rotated drive IQ to obtain quadrature component

// Quadrature portion of SSB drive signal
flevel_set level2(.clk(clk),
	.cosd(cosa), .sind(sina),
	.i_data(~drive_q), .i_gate(1'b1), .i_trig(1'b1),
	.q_data(drive_i), .q_gate(1'b1), .q_trig(1'b1),
	.o_data(out2));

wire signed [15:0] outf2 = ssb_flip ? ~out2 : out2;
wire signed [15:0] outk2 = enable ? outf2 : 0;

wire [15:0] dac2_ob0, dac2_ob1;  // offset binary outputs from afterburner
afterburner afterburner2(.clk(clk),
	.data({outk2,1'b0}), .coeff(aftb_coeff),
	.data_out0(dac2_ob0), .data_out1(dac2_ob1));

// afterburner returns offset-binary DAC words, but this module uses signed
// (twos-complement) for its output.  Thus the conversions below.
assign dac1_out0 = {~dac1_ob0[15], dac1_ob0[14:0]};
assign dac1_out1 = {~dac1_ob1[15], dac1_ob1[14:0]};
assign dac2_out0 = {~dac2_ob0[15], dac2_ob0[14:0]};
assign dac2_out1 = {~dac2_ob1[15], dac2_ob1[14:0]};

endmodule

// Synthesizes to 47 slices and 1 MULT18X18 at 166 MHz in XC3Sxxx-4 using XST-9.2.04i
//  Use parameter triple instead of preprocessor variable AFTERBURNER_TRIPLE
//  User port coeff instead of parameter coeff
// If the port coeff is set to a constant value, should synthesize identically
// There is a latency of 3 clock cycles (??)
// Note: The output of the module is Offset Binary
// [It is perhaps stupid to have that here and it should be moved into another module]

// CONCEPT: The mid point along the circle of a of 2 complex numbers that already lie
//          on a circle is not a plain average. To obtain the (real/imaginary) component
//          of this mid-point one has to multiply by what is called "coeff"
//          k = 0.5*sec(theta) .. where theta is the angle between the complex numbers

`timescale 1ns / 1ns
module afterburner(
	input clk,  // timespec 6.0 ns
	input signed [16:0] data,  // This is level set data [.. a_n1, a_n2 ..]
	input signed [15:0] coeff, // Coefficient to correct for  interpolation
	output [15:0] data_out0,   // Interpolated [coeff*[..(a_n1+a_n2), (a_n2+a_n3),..]]
	output [15:0] data_out1    // Untouched    [.. a_n1, a_n2 ..]
);

parameter triple=0;

// concept:  a1  k*(a1+a2)  a2  k*(a2+a3)  a3  ...
// where k = 0.5*sec(theta) = 0.5*sec(2*pi*11/28) = -0.63952
// to handle 55 MHz output at 70 MHz clk (140 MS/s data rate to DAC)

// num = 2  % or 8 for L-band
// den = 11
// coeff = floor(32768*0.5*sec(pi*num/den)+0.5)
// 19476  % or -25019 for L-band

reg signed [17:0] avg=0;
reg signed [16:0] data1=0, data2=0, data3=0, data4=0;
wire signed [16:0] thru = triple ? data4 : data3;
reg signed [33:0] prod=0;
reg signed [15:0] sat=0;
always @(posedge clk) begin
	data1 <= data;
	data2 <= data1;
	data3 <= data2;
	data4 <= data3;
	avg <= data + (triple ? data3 : data1);
	prod <= avg * coeff;  // scale by 32768
	sat <= (~(|prod[33:31]) | (&prod[33:31])) ? prod[31:16] : {prod[33],{15{~prod[33]}}};
end

// send offset binary to DAC (someone else needs to instantiate the DDR output cells)
assign data_out0 = ({~sat[15], sat[14:0]});
assign data_out1 = ({~thru[16], thru[15:1]});

endmodule

